    sentence = sentence[0].upper() + sentence[1:]

    # Capitalize proper nouns (simple heuristic: words after certain prepositions)
    import re
    def capitalize_proper_nouns(text):
        # Capitalize first word after "in", "of", "by", "at"
        text = re.sub(r'\b(in|of|by|at|for|to)\s+([a-z])', lambda m: m.group(1) + ' ' + m.group(2).upper(), text)
